INSERT INTO SYS_USER_API_KEY (
    USER_ID, API_KEY_NAME, API_KEY_PREFIX, API_KEY_HASH, API_KEY_STATUS,
    EXPIRE_TIME, LAST_USED_TIME, CREATE_TIME, UPDATE_TIME
) VALUES (
    #{userId}, #{apiKeyName}, #{apiKeyPrefix}, #{apiKeyHash}, #{apiKeyStatus},
    #{expireTime}, #{lastUsedTime}, #{createTime}, #{updateTime}
)

mapper.select:
SELECT 
FROM SYS_USER_API_KEY
WHERE API_KEY_ID = #{apiKeyId}
  AND USER_ID = #{userId}
LIMIT 1

mapper.update:
UPDATE SYS_USER_API_KEY
SET API_KEY_STATUS = 2,
    UPDATE_TIME = #{updateTime}
WHERE API_KEY_ID = #{apiKeyId}
  AND USER_ID = #{userId}

